#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, D;
        scanf("%d %d", &N, &D);
        long long sum = 0;
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
            sum += arr[i];
        }
        if (sum % N != 0) {
            printf("-1\n");
            continue;
        }
        long long target = sum / N;
        long long moves = 0;
        for (int i = 0; i < N; i++) {
            if (i + D < N) {
                moves += (arr[i] > target) ? arr[i] - target : target - arr[i];
            }
        }
        printf("%lld\n", moves);
    }
    return 0;
}

