import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int D = sc.nextInt();
            long sum = 0;
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
                sum += arr[i];
            }
            if (sum % N != 0) {
                System.out.println(-1);
                continue;
            }
            long target = sum / N;
            long moves = 0;
            for (int i = 0; i < N; i++) {
                if (i + D < N) {
                    moves += (arr[i] > target) ? arr[i] - target : target - arr[i];
                }
            }
            System.out.println(moves);
        }
    }
}

