for (let i = 0; i < T; i++) {
    const [N, D] = readline().split(' ').map(Number);
    const arr = readline().split(' ').map(Number);
    const sum = arr.reduce((a, b) => a + b, 0);
    if (sum % N !== 0) {
        console.log(-1);
        continue;
    }
    const target = sum / N;
    let moves = 0;
    for (let j = 0; j < N; j++) {
        if (j + D < N) {
            moves += Math.abs(arr[j] - target);
        }
    }
    console.log(moves);
}

